static void
Synth_dealloc(SynthObject *self)
{
    free(self->src.bits);
    Py_TYPE(self)->tp_free((PyObject *)self);
}

/* Copy a Python bytes (0/1 pattern) or None into src->bits (owned). */
static int
_attach_bytes(wfm_source_t *src, PyObject *obj)
{
    free(src->bits);
    src->bits   = NULL;
    src->n_bits = 0;
    if (!obj || obj == Py_None)
        return 1;
    if (!PyBytes_Check(obj)) {
        PyErr_SetString(PyExc_TypeError, "bits must be bytes or None");
        return 0;
    }
    Py_ssize_t nb = PyBytes_GET_SIZE(obj);
    if (nb <= 0)
        return 1;
    uint8_t *copy = (uint8_t *)malloc((size_t)nb);
    if (!copy) {
        PyErr_NoMemory();
        return 0;
    }
    memcpy(copy, PyBytes_AS_STRING(obj), (size_t)nb);
    src->bits   = copy;
    src->n_bits = (size_t)nb;
    return 1;
}

