/* Factory shared body: inject {type: <name>} into kwds, call the type. */
static PyObject *
_Synth_factory(const char *kind, PyObject *args, PyObject *kwds)
{
    PyObject *k = kwds ? PyDict_Copy(kwds) : PyDict_New();
    if (!k) return NULL;
    PyObject *v = PyUnicode_FromString(kind);
    if (!v || PyDict_SetItemString(k, "type", v) < 0) {
        Py_XDECREF(v);
        Py_DECREF(k);
        return NULL;
    }
    Py_DECREF(v);
    PyObject *r = PyObject_Call((PyObject *)&SynthType, args, k);
    Py_DECREF(k);
    return r;
}

