PyInit_wfm_compose(void)
{
    import_array();
    if (PyType_Ready(&SynthType) < 0) return NULL;
    if (PyType_Ready(&SegmentType) < 0) return NULL;
    if (PyType_Ready(&TimelineType) < 0) return NULL;
    if (PyType_Ready(&ComposerType) < 0) return NULL;
    PyObject *m = PyModule_Create(&_moduledef);
    if (!m) return NULL;
    Py_INCREF(&SynthType);
    PyModule_AddObject(m, "Synth", (PyObject *)&SynthType);
    Py_INCREF(&SegmentType);
    PyModule_AddObject(m, "Segment", (PyObject *)&SegmentType);
    Py_INCREF(&TimelineType);
    PyModule_AddObject(m, "Timeline", (PyObject *)&TimelineType);
    Py_INCREF(&ComposerType);
    PyModule_AddObject(m, "Composer", (PyObject *)&ComposerType);
    return m;
}
